using namespace std;



int getdigit(int x){

	int t=x,ret=0;

	while(t){

		ret++;

		t/=10;

	}

	return ret;

}



int cf(int x,int z){

	int ret=1;

	for(register int i=1;i<=z;i++){

		ret*=x;

	}

	return ret;

}



