	int a,b;

	scanf("%d%d",&a,&b);

	int t1=getdigit(b);

	int t2=cf(10,t1);

	int c=a*t2+b;

	//printf("%d %d %d\n",t1,t2,c);

	for(register int i=1;i<=1000;i++){

		if(i*i==c){

