using namespace std;



string a, b, c;



int work(int sum) {

	for (int i = 1; i * i <= sum; i++) {

		if (i * i == sum) {

			return 1;

		}

	}

	return 0;

}



int main() {

	cin >> a;

	cin >> b;

	c = a + b;

	int len = c.size();

	int sum = 0;

	for (int i = len - 1; i >= 0; i--) {

		sum += (c[i] - '0') * pow(10, len - i - 1);

	}

	if (work(sum)) {

		printf("Yes\n");

	}

	else {

		printf("No\n");

	}

}

